script:
frappe.ui.form.on('Customer', {
    custom_gstin: function(frm) {
        var gstin = (frm.doc.custom_gstin || '').trim().toUpperCase();
        if (!gstin) return;
        var re = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$/;
        if (!re.test(gstin)) {
            frappe.msgprint({
                title: 'Invalid GSTIN',
                message: 'GSTIN must be 15 characters in format: 22AAAAA0000A1Z5',
                indicator: 'red'
            });
            frm.set_value('custom_gstin', '');
            return;
        }
        frm.set_value('custom_gstin', gstin);
        var state_codes = {
            '01':'J&K','02':'HP','03':'Punjab','04':'Chandigarh','05':'Uttarakhand',
            '06':'Haryana','07':'Delhi','08':'Rajasthan','09':'UP','10':'Bihar',
            '11':'Sikkim','12':'Arunachal Pradesh','13':'Nagaland','14':'Manipur',
            '15':'Mizoram','16':'Tripura','17':'Meghalaya','18':'Assam',
            '19':'West Bengal','20':'Jharkhand','21':'Odisha','22':'Chhattisgarh',
            '23':'MP','24':'Gujarat','27':'Maharashtra','28':'AP','29':'Karnataka',
            '30':'Goa','32':'Kerala','33':'Tamil Nadu','36':'Telangana'
        };
        var state_code = gstin.substring(0, 2);
        var state = state_codes[state_code] || 'Unknown';
        var pan = gstin.substring(2, 12);
        frappe.show_alert({
            message: `✓ Valid GSTIN | State: ${state} | PAN: ${pan}`,
            indicator: 'green'
        }, 4);
        if (!frm.doc.tax_id) frm.set_value('tax_id', gstin);
    },
    validate: function(frm) {
        var gstin = (frm.doc.custom_gstin || '').trim();
        if (!gstin) return;
        var re = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$/;
        if (!re.test(gstin)) {
            frappe.throw('Invalid GSTIN format. Please enter a valid 15-character GSTIN.');
        }
    }
});
